static inline const font_terminal_ascii_5x7_glyph_record_t *font_terminal_ascii_5x7_find_glyph(uint32_t codepoint) {
    size_t left = 0;
    size_t right = FONT_TERMINAL_ASCII_5X7_GLYPH_COUNT;

    while (left < right) {
        size_t mid = left + ((right - left) / 2u);
        uint32_t current = font_terminal_ascii_5x7_glyph_records[mid].codepoint;

        if (current == codepoint) {
            return &font_terminal_ascii_5x7_glyph_records[mid];
        }
        if (current < codepoint) {
            left = mid + 1u;
        } else {
            right = mid;
        }
    }

    return NULL;
}

static inline const font_terminal_ascii_5x7_glyph_record_t *font_terminal_ascii_5x7_glyph(uint32_t codepoint) {
    const font_terminal_ascii_5x7_glyph_record_t *glyph = font_terminal_ascii_5x7_find_glyph(codepoint);
    if (glyph != NULL) {
        return glyph;
    }
    return font_terminal_ascii_5x7_find_glyph(FONT_TERMINAL_ASCII_5X7_FALLBACK_CODEPOINT);
}

static inline uint8_t font_terminal_ascii_5x7_pixel(const font_terminal_ascii_5x7_glyph_record_t *glyph, uint16_t x, uint16_t y) {
    if (glyph == NULL || x >= glyph->width || y >= glyph->height) {
        return 0u;
    }

    const uint32_t offset = glyph->data_offset + ((uint32_t)y * FONT_TERMINAL_ASCII_5X7_ROW_STRIDE) + ((uint32_t)x / 8u);
    const uint8_t byte = font_terminal_ascii_5x7_glyph_data[offset];
    const uint8_t bit = (uint8_t)(7u - (x & 7u));
    return (uint8_t)((byte >> bit) & 1u);
}

